import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../contexts/AuthContext';
import { OportunidadeInput } from '../types';

const NovaOportunidade: React.FC = () => {
  const { user } = useAuth();
  const navigate = useNavigate();
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [formData, setFormData] = useState<OportunidadeInput>({
    titulo: '',
    descricao: '',
    tipo: 'Estágio',
    requisitos: [],
    beneficios: [],
    data_inicio: '',
    data_fim: '',
  });

  const tiposOportunidade = [
    'Estágio',
    'Emprego',
    'Aprendizagem',
    'Projeto',
    'Curso',
    'Voluntariado',
    'Outro'
  ];

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleArrayChange = (name: string, value: string) => {
    // Converter string em array (vírgulas ou linhas novas)
    const items = value.split(/[,\n]+/).map(item => item.trim()).filter(item => item);
    
    setFormData(prev => ({ ...prev, [name]: items }));
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    
    if (!formData.titulo || !formData.descricao || !formData.tipo) {
      setError('Preencha todos os campos obrigatórios');
      return;
    }
    
    setLoading(true);
    setError(null);
    
    try {
      const response = await fetch('/api/oportunidades', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify(formData)
      });
      
      if (!response.ok) {
        throw new Error('Erro ao criar oportunidade');
      }
      
      const data = await response.json();
      
      // Redirecionar para a página de detalhes da oportunidade criada
      navigate(`/instituicao-contratante/oportunidades/${data.id}`);
    } catch (error) {
      console.error('Erro:', error);
      setError('Erro ao criar oportunidade. Por favor, tente novamente.');
    } finally {
      setLoading(false);
    }
  };

  const handleCancel = () => {
    navigate('/instituicao-contratante/oportunidades');
  };

  return (
    <div className="container mx-auto px-4 py-8">
      <div className="mb-6">
        <h1 className="text-2xl font-bold text-cursor-text-primary">Nova Oportunidade</h1>
        <p className="text-cursor-text-secondary mt-1">
          Crie uma nova oportunidade para jovens talentos
        </p>
      </div>

      <div className="bg-white rounded-lg shadow overflow-hidden">
        <div className="p-6">
          <form onSubmit={handleSubmit} className="space-y-6">
            {error && (
              <div className="p-4 bg-red-50 border-l-4 border-red-500 text-red-700">
                <p>{error}</p>
              </div>
            )}
            
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              {/* Coluna da esquerda */}
              <div className="space-y-6">
                <div>
                  <label htmlFor="titulo" className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Título*
                  </label>
                  <input
                    type="text"
                    id="titulo"
                    name="titulo"
                    value={formData.titulo}
                    onChange={handleChange}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:ring-1 focus:ring-cursor-primary focus:outline-none"
                    placeholder="Ex: Estágio em Desenvolvimento Web"
                    required
                  />
                </div>
                
                <div>
                  <label htmlFor="tipo" className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Tipo de Oportunidade*
                  </label>
                  <select
                    id="tipo"
                    name="tipo"
                    value={formData.tipo}
                    onChange={handleChange}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:ring-1 focus:ring-cursor-primary focus:outline-none"
                    required
                  >
                    {tiposOportunidade.map(tipo => (
                      <option key={tipo} value={tipo}>{tipo}</option>
                    ))}
                  </select>
                </div>
                
                <div>
                  <label htmlFor="data_inicio" className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Data de Início
                  </label>
                  <input
                    type="date"
                    id="data_inicio"
                    name="data_inicio"
                    value={formData.data_inicio}
                    onChange={handleChange}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:ring-1 focus:ring-cursor-primary focus:outline-none"
                  />
                </div>
                
                <div>
                  <label htmlFor="data_fim" className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Data de Término
                  </label>
                  <input
                    type="date"
                    id="data_fim"
                    name="data_fim"
                    value={formData.data_fim}
                    onChange={handleChange}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:ring-1 focus:ring-cursor-primary focus:outline-none"
                  />
                </div>
              </div>
              
              {/* Coluna da direita */}
              <div className="space-y-6">
                <div>
                  <label htmlFor="descricao" className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Descrição*
                  </label>
                  <textarea
                    id="descricao"
                    name="descricao"
                    value={formData.descricao}
                    onChange={handleChange}
                    rows={5}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:ring-1 focus:ring-cursor-primary focus:outline-none"
                    placeholder="Descreva detalhes sobre a oportunidade..."
                    required
                  />
                </div>
                
                <div>
                  <label htmlFor="requisitos" className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Requisitos (um por linha)
                  </label>
                  <textarea
                    id="requisitos"
                    name="requisitos"
                    value={formData.requisitos?.join('\n')}
                    onChange={(e) => handleArrayChange('requisitos', e.target.value)}
                    rows={3}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:ring-1 focus:ring-cursor-primary focus:outline-none"
                    placeholder="Conhecimento básico em HTML, CSS, JavaScript"
                  />
                </div>
                
                <div>
                  <label htmlFor="beneficios" className="block text-sm font-medium text-cursor-text-tertiary mb-1">
                    Benefícios (um por linha)
                  </label>
                  <textarea
                    id="beneficios"
                    name="beneficios"
                    value={formData.beneficios?.join('\n')}
                    onChange={(e) => handleArrayChange('beneficios', e.target.value)}
                    rows={3}
                    className="w-full p-3 rounded-lg bg-cursor-bg text-cursor-text-primary border border-cursor-border focus:border-cursor-primary focus:ring-1 focus:ring-cursor-primary focus:outline-none"
                    placeholder="Bolsa auxílio, Vale transporte, Vale refeição"
                  />
                </div>
              </div>
            </div>
            
            <div className="flex justify-end space-x-3 pt-4">
              <button
                type="button"
                onClick={handleCancel}
                className="px-4 py-2 border border-cursor-border rounded-md text-cursor-text-primary bg-white hover:bg-cursor-bg"
                disabled={loading}
              >
                Cancelar
              </button>
              <button
                type="submit"
                className="px-4 py-2 bg-cursor-primary text-white rounded-md hover:bg-cursor-primary-dark flex items-center"
                disabled={loading}
              >
                {loading ? (
                  <>
                    <svg className="animate-spin -ml-1 mr-2 h-4 w-4 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle>
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path>
